using System.Collections.Generic;
using UnityEngine;

public partial class PlayerProgress : MonoBehaviour
{
    // ---------------- Progressão por Mundo (Menu de Pausa: Progresso — Tarefa #11) ----------------

    /// <summary>O jogador já descobriu quantos Runas/Animais/NPCs/Sussurros/Missões existem neste mundo (ver WorldProgress.totalsDiscovered).</summary>
    public bool AreWorldTotalsDiscovered(string worldId) => GetOrCreateWorldProgress(worldId).totalsDiscovered;
    public bool AreWorldTotalsDiscovered(WorldData world) => world != null && AreWorldTotalsDiscovered(world.worldId);

    /// <summary>Marca que o jogador já descobriu os totais deste mundo — a secção Progresso passa a mostrar "X/TOTAL" em vez de "X/?".</summary>
    public void MarkWorldTotalsDiscovered(string worldId)
    {
        if (string.IsNullOrEmpty(worldId)) return;
        GetOrCreateWorldProgress(worldId).totalsDiscovered = true;
    }

    public void MarkWorldTotalsDiscovered(WorldData world)
    {
        if (world != null) MarkWorldTotalsDiscovered(world.worldId);
    }

    private WorldProgress GetOrCreateWorldProgress(string worldId)
    {
        for (int i = 0; i < worldProgress.Count; i++)
            if (worldProgress[i].worldId == worldId) return worldProgress[i];

        var created = new WorldProgress { worldId = worldId };
        worldProgress.Add(created);
        return created;
    }

    // ---------------- Diário — Pistas de Missão e Rumores (Sistema de Pistas/Rumores) ----------------

    /// <summary>Combina "missionId" e "clueId" no formato usado por "_obtainedClueIds".</summary>
    private static string CombineClueId(string missionId, string clueId) => $"{missionId}/{clueId}";

    /// <summary>True se a pista "clueId" da missão "missionId" já foi obtida.</summary>
    public bool HasClue(string missionId, string clueId)
    {
        if (string.IsNullOrEmpty(missionId) || string.IsNullOrEmpty(clueId)) return false;
        return _obtainedClueIds.Contains(CombineClueId(missionId, clueId));
    }

    public bool HasClue(MissionData mission, string clueId) => mission != null && HasClue(mission.missionId, clueId);

    /// <summary>Regista a pista "clueId" da missão "missionId" como obtida (idempotente).</summary>
    public void MarkClueObtained(string missionId, string clueId)
    {
        if (string.IsNullOrEmpty(missionId) || string.IsNullOrEmpty(clueId)) return;

        string combined = CombineClueId(missionId, clueId);
        if (!_obtainedClueIds.Contains(combined)) _obtainedClueIds.Add(combined);
    }

    public void MarkClueObtained(MissionData mission, string clueId)
    {
        if (mission != null) MarkClueObtained(mission.missionId, clueId);
    }

    /// <summary>True se o rumor "rumorId" já foi ouvido (Action_AddRumor) — aparece na secção "Rumores" do Diário.</summary>
    public bool HasHeardRumor(string rumorId) => !string.IsNullOrEmpty(rumorId) && _heardRumorIds.Contains(rumorId);

    public void MarkRumorHeard(string rumorId)
    {
        if (!string.IsNullOrEmpty(rumorId) && !_heardRumorIds.Contains(rumorId))
            _heardRumorIds.Add(rumorId);
    }

    /// <summary>True se o rumor "rumorId" já foi marcado como "encontrado" (Action_MarkRumorFound) — mostra o ícone de "Check".</summary>
    public bool IsRumorFound(string rumorId) => !string.IsNullOrEmpty(rumorId) && _foundRumorIds.Contains(rumorId);

    public void MarkRumorFound(string rumorId)
    {
        if (!string.IsNullOrEmpty(rumorId) && !_foundRumorIds.Contains(rumorId))
            _foundRumorIds.Add(rumorId);
    }

    // ---------------- Percentagem Total do Save (Menu de Pausa: Progresso — Tarefa #11) ----------------

    /// <summary>
    /// Percentagem total de conclusão do save (0–100, ou exactamente 101 —
    /// GDD: "100% = Emblema de Gaia; Provação = Emblema de Apolo;
    /// Gaia + Apolo = 101% e Emblema de Zeus").
    ///
    /// <b>Critérios por área (allAreas):</b>
    ///   • Runas de Gaia (totalRunas)
    ///   • NPCs resgatados (totalNpcsToRescue)
    ///   • Sussurros da Terra adquiridos (whispersFound): comprados no Contador
    ///     de Histórias com Ecos Perdidos — GDD: "Os Sussurros não ficam
    ///     espalhados como pickups." Não há fase de "entrega" no GDD;
    ///     whispersDelivered NÃO entra neste cálculo (Task #5).
    ///   • Baús (totalChests)
    ///   • Fragmentos Vitais (totalFragments)
    ///   • Desafio opcional concluído (hasOptionalChallenge)
    ///   • Melodias Selvagens recolhidas (totalMelodies)
    ///
    /// <b>Critérios globais:</b>
    ///   • Formas de animais NÃO-secretas libertadas (allForms, isSecretForm=false)
    ///   • Missões concluídas (allMissions)
    ///   • Emblemas de mundo (allEmblems onde !isBonus &amp;&amp; !isGaiaEmblem
    ///     &amp;&amp; !isApoloEmblem — normalmente os 6 emblemas de mundo)
    ///
    /// <b>Excluídos do cálculo:</b>
    ///   • Formas secretas (isSecretForm = true)
    ///   • Emblema de Gaia, Emblema de Apolo, Emblema de Zeus (isGaiaEmblem /
    ///     isApoloEmblem / isBonus) — contam apenas para a regra dos 101%
    ///   • Sementes, Ecos Perdidos, inimigos
    ///
    /// <b>Regra especial de 101%:</b>
    ///   Devolve exactamente 101 se e só se Emblema de Gaia E Emblema de Apolo
    ///   estiverem ambos obtidos. Em todos os outros casos: clamp(0, 100).
    /// </summary>
    public int GetTotalCompletionPercent(List<AreaData> allAreas, List<AnimalFormData> allForms, List<MissionData> allMissions, List<EmblemData> allEmblems)
    {
        int total = 0;
        int found = 0;

        if (allAreas != null)
        {
            foreach (var area in allAreas)
            {
                if (area == null) continue;
                var ap = GetOrCreateAreaProgress(area.areaId);

                if (area.totalRunas > 0) { total += area.totalRunas; found += Mathf.Min(ap.runasFound, area.totalRunas); }
                if (area.totalNpcsToRescue > 0) { total += area.totalNpcsToRescue; found += Mathf.Min(ap.npcsRescued, area.totalNpcsToRescue); }

                // Task #5 / GDD: Sussurros são adquiridos (comprados no Contador de Histórias)
                // — não existem como pickups físicos nem têm fase de "entrega". Só
                // whispersFound conta; whispersDelivered foi removido do cálculo.
                if (area.totalWhispers > 0) { total += area.totalWhispers; found += Mathf.Min(ap.whispersFound, area.totalWhispers); }

                if (area.totalChests > 0) { total += area.totalChests; found += Mathf.Min(ap.chestsFound, area.totalChests); }
                if (area.totalFragments > 0) { total += area.totalFragments; found += Mathf.Min(ap.fragmentsFound, area.totalFragments); }

                if (area.hasOptionalChallenge)
                {
                    total += 1;
                    if (ap.challengeCompleted) found += 1;
                }

                if (area.totalMelodies > 0) { total += area.totalMelodies; found += Mathf.Min(ap.melodiesFound, area.totalMelodies); }
            }
        }

        if (allForms != null)
        {
            foreach (var form in allForms)
            {
                if (form == null) continue;
                if (form.isSecretForm) continue; // formas secretas excluídas do cálculo.

                total += 1;
                if (HasFreedAnimal(form.formId)) found += 1;
            }
        }

        if (allMissions != null)
        {
            var missionManager = MissionManager.Instance;
            foreach (var mission in allMissions)
            {
                if (mission == null) continue;
                total += 1;
                if (missionManager != null && missionManager.IsMissionCompleted(mission)) found += 1;
            }
        }

        // Emblemas: só os 6 de mundo (não-bónus, não-Gaia, não-Apolo) contam.
        // Emblemas de Gaia e Apolo são rastreados separadamente para a regra dos 101%.
        bool gaiaObtained = false;
        bool apoloObtained = false;

        if (allEmblems != null)
        {
            var vars = GameVariables.Instance;
            foreach (var emblem in allEmblems)
            {
                if (emblem == null) continue;
                bool obtained = vars != null && !string.IsNullOrEmpty(emblem.obtainedVariable) && vars.GetBool(emblem.obtainedVariable);

                if (emblem.isGaiaEmblem)  { if (obtained) gaiaObtained  = true; continue; }
                if (emblem.isApoloEmblem) { if (obtained) apoloObtained = true; continue; }
                if (emblem.isBonus) continue; // outros bónus (ex: Emblema de Zeus) — excluídos.

                total += 1;
                if (obtained) found += 1;
            }
        }

        if (total <= 0) return 0;

        // GDD: 101% é exclusivo de Gaia + Apolo — nunca mais do que isso,
        // e só quando basePercent já atingiu 100 (Task #27: evitar 101% antes do 100%).
        int basePercent = Mathf.Clamp(Mathf.RoundToInt(100f * found / total), 0, 100);
        return (gaiaObtained && apoloObtained && basePercent == 100) ? 101 : basePercent;
    }

    // ---------------- Bosses / Mundo ----------------

    public bool HasDefeatedBoss(string worldId) => !string.IsNullOrEmpty(worldId) && defeatedBossWorldIds.Contains(worldId);
    public bool HasDefeatedBoss(WorldData world) => world != null && HasDefeatedBoss(world.worldId);

    public void SetBossDefeated(string worldId)
    {
        if (string.IsNullOrEmpty(worldId)) return;
        if (!defeatedBossWorldIds.Contains(worldId)) defeatedBossWorldIds.Add(worldId);
        if (!pendingPostBossReturnWorldIds.Contains(worldId)) pendingPostBossReturnWorldIds.Add(worldId);

        // Verifica emblemas após boss derrotado — pode desbloquear emblema de mundo
        // e, por sua vez, o boss alternativo (Tarefa #32).
        EmblemManager.Instance?.CheckAll();
    }

    public void SetBossDefeated(WorldData world)
    {
        if (world != null) SetBossDefeated(world.worldId);
    }

    /// <summary>O jogador venceu o boss deste mundo e ainda não passou pelo evento de "regresso".</summary>
    public bool IsReturningAfterBoss(string worldId) => pendingPostBossReturnWorldIds.Contains(worldId);
    public bool IsReturningAfterBoss(WorldData world) => world != null && IsReturningAfterBoss(world.worldId);

    /// <summary>Chamar quando o evento de "regresso pós-boss" terminar, para não disparar de novo.</summary>
    public void ClearReturningAfterBoss(string worldId) => pendingPostBossReturnWorldIds.Remove(worldId);
    public void ClearReturningAfterBoss(WorldData world)
    {
        if (world != null) ClearReturningAfterBoss(world.worldId);
    }

    // ---------------- Mapa-Múndi — Áreas Desbloqueadas ----------------

    public bool IsAreaUnlocked(string areaId) => !string.IsNullOrEmpty(areaId) && unlockedAreaIds.Contains(areaId);
    public bool IsAreaUnlocked(AreaData area) => area != null && IsAreaUnlocked(area.areaId);

    /// <summary>
    /// Desbloqueia "areaId" sem cobrar Runas (uso interno — vilas auto-desbloqueadas,
    /// área de boss libertada pela missão principal, ou desbloqueios via debug/editor).
    /// Para o fluxo normal "botão Desbloquear" usar <see cref="TryUnlockArea(AreaData)"/>.
    /// Devolve true se a área passou de bloqueada para desbloqueada agora.
    /// </summary>
    public bool UnlockArea(string areaId)
    {
        if (string.IsNullOrEmpty(areaId) || unlockedAreaIds.Contains(areaId)) return false;

        unlockedAreaIds.Add(areaId);
        AreaUnlockedOnMap?.Invoke(areaId);
        return true;
    }

    public bool UnlockArea(AreaData area) => area != null && UnlockArea(area.areaId);

    /// <summary>
    /// Tenta desbloquear "area" no Mapa-Múndi pelo fluxo normal (botão "Desbloquear"
    /// do painel). Áreas <see cref="AreaData.MapNodeType.Vila"/> e
    /// <see cref="AreaData.MapNodeType.Boss"/> têm custo 0 (vilas são auto-desbloqueadas
    /// pelo WorldMapController; bosses são libertados por missão — nenhum dos dois
    /// deve, normalmente, passar pelo botão "Desbloquear", mas o método continua
    /// seguro/gratuito para esses casos). Para áreas Normal, cobra
    /// <see cref="AreaData.unlockCost"/> em Runas de Gaia via
    /// <see cref="TrySpendResource(PlayerResourceType, int)"/> — só desbloqueia se
    /// houver saldo suficiente. Devolve true se a área ficou desbloqueada
    /// (já estava desbloqueada também conta como sucesso, sem cobrar de novo).
    /// </summary>
    public bool TryUnlockArea(AreaData area)
    {
        if (area == null) return false;
        if (IsAreaUnlocked(area)) return true;

        int cost = area.mapNodeType == AreaData.MapNodeType.Normal ? Mathf.Max(0, area.unlockCost) : 0;

        if (cost > 0 && !TrySpendResource(PlayerResourceType.RunasDeGaia, cost))
            return false;

        return UnlockArea(area.areaId);
    }

    // ---------------- Mapa-Múndi — Boss ----------------

    /// <summary>O jogador já encontrou o boss deste mundo pelo menos uma vez (vitória OU derrota) — painel mostra AreaData.bossDisplayName em vez de "????????".</summary>
    public bool HasDiscoveredBoss(string worldId) => !string.IsNullOrEmpty(worldId) && discoveredBossWorldIds.Contains(worldId);
    public bool HasDiscoveredBoss(WorldData world) => world != null && HasDiscoveredBoss(world.worldId);

    public void MarkBossDiscovered(string worldId)
    {
        if (!string.IsNullOrEmpty(worldId) && !discoveredBossWorldIds.Contains(worldId))
            discoveredBossWorldIds.Add(worldId);
    }

    public void MarkBossDiscovered(WorldData world)
    {
        if (world != null) MarkBossDiscovered(world.worldId);
    }

    /// <summary>A animação de desbloqueio da área do boss (câmara viaja até à Coroa, novo ramo ilumina-se) já foi reproduzida para este mundo — não repetir.</summary>
    public bool HasPlayedBossUnlockAnimation(string worldId) => !string.IsNullOrEmpty(worldId) && bossUnlockAnimationPlayedWorldIds.Contains(worldId);
    public bool HasPlayedBossUnlockAnimation(WorldData world) => world != null && HasPlayedBossUnlockAnimation(world.worldId);

    public void MarkBossUnlockAnimationPlayed(string worldId)
    {
        if (!string.IsNullOrEmpty(worldId) && !bossUnlockAnimationPlayedWorldIds.Contains(worldId))
            bossUnlockAnimationPlayedWorldIds.Add(worldId);
    }

    public void MarkBossUnlockAnimationPlayed(WorldData world)
    {
        if (world != null) MarkBossUnlockAnimationPlayed(world.worldId);
    }

    // ---- Área Secreta de Apolo ----

    [Header("Mapa-Múndi — Área Secreta de Apolo")]
    [Tooltip("True quando a animação de desbloqueio da área secreta de Apolo (câmara viaja até à nova área) já foi reproduzida. Garante que a sequência só acontece uma vez.")]
    [SerializeField] private bool apoloAreaUnlockAnimationPlayed;

    /// <summary>A animação de desbloqueio da área secreta de Apolo já foi reproduzida — não repetir.</summary>
    public bool HasPlayedApoloAreaUnlockAnimation() => apoloAreaUnlockAnimationPlayed;

    /// <summary>Marca que a animação de desbloqueio da área secreta de Apolo já foi reproduzida.</summary>
    public void MarkApoloAreaUnlockAnimationPlayed() => apoloAreaUnlockAnimationPlayed = true;
}
